// scripts/gen-exam-index.mjs — regenerate content/exam/bank/index.ts from the per-unit bank files.
// Run after adding/removing a bank file: `node scripts/gen-exam-index.mjs`.
import fs from 'fs';
import path from 'path';

const dir = path.join(process.cwd(), 'content', 'exam', 'bank');
const files = fs
  .readdirSync(dir)
  .filter((f) => f.endsWith('.ts') && f !== 'index.ts')
  .map((f) => f.replace(/\.ts$/, ''))
  .sort();

const importName = (id) => 'b_' + id.replace(/[^a-zA-Z0-9]/g, '_');
const lines = [
  '// content/exam/bank/index.ts — GENERATED by scripts/gen-exam-index.mjs. Do not edit by hand.',
  "import type { ExamItem } from '../types';",
  ...files.map((id) => `import ${importName(id)} from './${id}';`),
  '',
  'export const SECTION_BANK: Record<string, ExamItem[]> = {',
  ...files.map((id) => `  '${id}': ${importName(id)},`),
  '};',
  '',
];
fs.writeFileSync(path.join(dir, 'index.ts'), lines.join('\n'));
console.log(`wrote index.ts with ${files.length} unit banks`);
